// ── ALLERGEN CHIP ─────────────────────────────────────────────
function AlgChip({label,selected,prominent,small,onClick}) {
  return (
    <button onClick={onClick} style={{
      padding:prominent?"6px 13px":small?"4px 9px":"5px 11px",
      borderRadius:20,cursor:"pointer",transition:"all 0.12s",
      border:selected?"none":prominent?`1.5px solid ${T.coral}`:`1.5px solid ${T.border}`,
      background:selected?T.coral:prominent?T.coralLight:T.bg,
      color:selected?"white":prominent?T.coralDark:T.sub,
      fontSize:prominent?13:small?11:12,
      fontWeight:selected||prominent?"600":"400",
      touchAction:"manipulation",
    }}>{label}</button>
  );
}

// ── ALLERGEN PICKER ───────────────────────────────────────────
function AllergenPicker({likely=[],possible=[],onDone}) {
  const [sel,setSel]=useState([]);
  const toggle=a=>setSel(s=>s.includes(a)?s.filter(x=>x!==a):[...s,a]);
  const others=ALLERGENS.filter(a=>!likely.includes(a)&&!possible.includes(a));
  return (
    <div style={{background:T.card,borderRadius:16,padding:14,border:`1px solid ${T.border}`,maxWidth:290}}>
      {likely.length>0&&<Section label="LIKELY">{likely.map(a=><AlgChip key={a} label={a} prominent selected={sel.includes(a)} onClick={()=>toggle(a)}/>)}</Section>}
      {possible.length>0&&<Section label="POSSIBLY">{possible.map(a=><AlgChip key={a} label={a} selected={sel.includes(a)} onClick={()=>toggle(a)}/>)}</Section>}
      <Section label="ADD MORE">{others.map(a=><AlgChip key={a} label={a} small selected={sel.includes(a)} onClick={()=>toggle(a)}/>)}</Section>
      <button onClick={()=>onDone(sel)} style={{width:"100%",background:T.coral,color:"white",border:"none",borderRadius:11,padding:"11px 0",fontSize:14,fontWeight:"700",cursor:"pointer",touchAction:"manipulation"}}>
        Log it →
      </button>
    </div>
  );
}
function Section({label,children}) {
  return <div style={{marginBottom:10}}><p style={{margin:"0 0 7px",fontSize:10,fontWeight:"700",color:T.muted,letterSpacing:"0.9px",textTransform:"uppercase"}}>{label}</p><div style={{display:"flex",flexWrap:"wrap",gap:5}}>{children}</div></div>;
}

// ── SEVERITY SLIDER ───────────────────────────────────────────
function SeveritySlider({value,onChange,onConfirm,label}) {
  const labels=["Clear","Very mild","Mild","Moderate","Significant","Severe"];
  const colors=["#4CAF82","#8BC34A","#FFC107","#FF9800","#F44336","#B71C1C"];
  return (
    <div style={{background:T.card,borderTop:`1px solid ${T.border}`,padding:"14px 20px 22px"}}>
      <p style={{margin:"0 0 3px",fontSize:12,color:T.sub,textAlign:"center"}}>{label}</p>
      <p style={{margin:"0 0 14px",fontSize:23,fontWeight:"800",textAlign:"center",color:colors[value]}}>{labels[value]}</p>
      <div style={{display:"flex",alignItems:"center",gap:12}}>
        <span style={{fontSize:11,color:T.muted}}>0</span>
        <input type="range" min="0" max="5" step="1" value={value} onChange={e=>onChange(+e.target.value)} style={{flex:1,accentColor:colors[value]}}/>
        <span style={{fontSize:11,color:T.muted}}>5</span>
        <button onClick={onConfirm} style={{background:T.coral,color:"white",border:"none",borderRadius:20,padding:"9px 20px",fontSize:14,fontWeight:"700",cursor:"pointer",touchAction:"manipulation"}}>Done</button>
      </div>
    </div>
  );
}

// ── BUBBLE ────────────────────────────────────────────────────
function Bubble({msg,onAllergenDone}) {
  const isPatch=msg.role==="patch";
  return (
    <div style={{display:"flex",flexDirection:"column",alignItems:isPatch?"flex-start":"flex-end",padding:"2px 14px",gap:3}}>
      {msg.image&&<img src={msg.image} alt="" style={{maxWidth:"65%",borderRadius:14,border:`1px solid ${T.border}`,display:"block"}}/>}
      {msg.text&&(
        <div style={{
          maxWidth:"76%",
          background:isPatch?T.bubblePatch:T.bubbleUser,
          border:isPatch?`1px solid ${T.border}`:"none",
          borderRadius:isPatch?"18px 18px 18px 4px":"18px 18px 4px 18px",
          padding:"10px 14px",fontSize:14.5,lineHeight:1.5,
          color:T.text,whiteSpace:"pre-wrap",
        }}>{msg.text}</div>
      )}
      {msg.allergenPicker&&!msg.allergenDone&&(
        <div style={{maxWidth:"90%"}}>
          <AllergenPicker likely={msg.allergenPicker.likely} possible={msg.allergenPicker.possible} onDone={sel=>onAllergenDone(msg.id,sel)}/>
        </div>
      )}
      {msg.allergenDone&&(
        <div style={{fontSize:12,color:T.coral,fontWeight:"700",padding:"4px 12px",background:T.coralLight,borderRadius:20,border:`1px solid ${T.coralMid}`}}>✓ Logged</div>
      )}
      <span style={{fontSize:11,color:T.muted,padding:"0 3px"}}>{fmtTime(msg.ts)}</span>
    </div>
  );
}

// ── CONTACT ROW ───────────────────────────────────────────────
function CRow({left,name,sub,right,unread,onTap,onAvatarTap}) {
  const [pressed,setPressed]=useState(false);
  return (
    <div onClick={onTap} onMouseDown={()=>setPressed(true)} onMouseUp={()=>setPressed(false)} onMouseLeave={()=>setPressed(false)}
      onTouchStart={()=>setPressed(true)} onTouchEnd={()=>setPressed(false)}
      style={{display:"flex",alignItems:"center",gap:12,padding:"11px 16px",cursor:"pointer",background:pressed?T.bg:T.card,transition:"background 0.1s",userSelect:"none",touchAction:"manipulation"}}>
      <div onClick={e=>{e.stopPropagation();onAvatarTap?.();}} style={{flexShrink:0}}>{left}</div>
      <div style={{flex:1,minWidth:0}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <p style={{margin:0,fontSize:15,fontWeight:"600",color:T.text,letterSpacing:"-0.2px"}}>{name}</p>
          {right}
        </div>
        <p style={{margin:"2px 0 0",fontSize:13,color:T.sub,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{sub}</p>
      </div>
      {unread&&<div style={{width:10,height:10,borderRadius:"50%",background:T.coral,flexShrink:0}}/>}
    </div>
  );
}

